"use client";

import Image from "next/image";
import Link from "next/link";
import { ArrowRight } from "lucide-react";
import { useEffect, useState } from "react";
import { useScrollReveal } from "@/lib/hooks/useScrollReveal";

interface FlashDealData {
  enabled: boolean;
  backgroundImage: string;
  badgeText: string;
  heading: string;
  subtext: string;
  buttonText: string;
  buttonUrl: string;
  endsAt: string;
  discountBadge: {
    enabled: boolean;
    text: string;
    percentage: string;
  };
}

interface TimeLeft {
  days: number;
  hours: number;
  mins: number;
  secs: number;
}

const DEFAULT_DATA: FlashDealData = {
  enabled: true,
  backgroundImage: "/images/landing/flash-deal/flash-deal.png",
  badgeText: "Flash Deal",
  heading: "Grab it before\nit ends.",
  subtext: "Up to 50% off on premium fitness equipment.",
  buttonText: "Shop Now",
  buttonUrl: "/shop?has_flash_deal=true",
  endsAt: "",
  discountBadge: {
    enabled: true,
    text: "Up to",
    percentage: "40%",
  },
};

function getTimeLeft(endsAt: string): TimeLeft {
  const diff = Math.max(0, new Date(endsAt).getTime() - Date.now());
  const totalSeconds = Math.floor(diff / 1000);
  return {
    days: Math.floor(totalSeconds / 86400),
    hours: Math.floor((totalSeconds % 86400) / 3600),
    mins: Math.floor((totalSeconds % 3600) / 60),
    secs: totalSeconds % 60,
  };
}

export function FlashDealSection() {
  const sectionRef = useScrollReveal();
  const [data, setData] = useState<FlashDealData>(DEFAULT_DATA);
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, mins: 0, secs: 0 });

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch("/api/hero-sections");
        if (response.ok) {
          const result = await response.json();
          if (result.flashDealSection) {
            setData(result.flashDealSection);
          }
        }
      } catch (error) {
        console.error("Error fetching flash deal data:", error);
      }
    };

    fetchData();
  }, []);

  useEffect(() => {
    if (!data.endsAt) {
      setTimeLeft({ days: 0, hours: 0, mins: 0, secs: 0 });
      return;
    }

    setTimeLeft(getTimeLeft(data.endsAt));
    const timer = setInterval(() => {
      setTimeLeft(getTimeLeft(data.endsAt));
    }, 1000);

    return () => clearInterval(timer);
  }, [data.endsAt]);

  if (!data.enabled) {
    return null;
  }

  return (
    <section ref={sectionRef as React.RefObject<HTMLElement>} className="w-full bg-white px-4 py-8 md:px-6 md:py-12">
      <div className="mx-auto w-full max-w-[1400px] px-4 md:px-6">
        <div data-reveal="scale" className="relative h-[684px] w-full overflow-hidden rounded-xs md:h-[500px] lg:h-[684px]">
          {/* Background Image */}
          <div className="absolute inset-0 h-full w-full overflow-hidden">
            <Image
              src={data.backgroundImage}
              alt="Flash Deal"
              fill
              className="object-cover object-center will-change-transform"
              sizes="(max-width: 768px) 100vw, (max-width: 1200px) 100vw, 100vw"
              priority
            />
          </div>

          {/* Gradient Overlay */}
          <div className="absolute inset-0 bg-gradient-to-r from-black/90 via-black/50 to-transparent pointer-events-none" />

          {/* Content */}
          <div className="absolute inset-y-0 left-0 flex max-w-[600px] flex-col justify-center px-6 md:px-16 z-10">
            <span className="mb-2 text-lg font-medium italic text-yellow-400 md:text-xl">
              {data.badgeText}
            </span>

            <h2 className="mb-4 text-4xl font-bold leading-tight text-white md:text-5xl lg:text-6xl">
              {data.heading.split("\n").map((line, index) => (
                <span key={index}>
                  {line}
                  {index < data.heading.split("\n").length - 1 && <br />}
                </span>
              ))}
            </h2>

            <p className="mb-8 text-base text-gray-200 md:text-lg">
              {data.subtext}
            </p>

            {/* Countdown Timer */}
            {data.endsAt && (
              <div className="mb-8 flex gap-3 md:gap-4">
                <TimeUnit value={timeLeft.days} label="Days" />
                <TimeUnit value={timeLeft.hours} label="Hours" />
                <TimeUnit value={timeLeft.mins} label="Mins" />
                <TimeUnit value={timeLeft.secs} label="Sec" />
              </div>
            )}

            <Link
              href={data.buttonUrl}
              className="inline-flex h-12 w-fit items-center gap-2 rounded-xs bg-yellow-400 px-8 text-[16px] font-semibold text-black transition-colors hover:bg-yellow-500"
            >
              {data.buttonText} <ArrowRight className="h-4 w-4" />
            </Link>
          </div>

          {/* Discount Badge */}
          {data.discountBadge.enabled && (
            <div className="absolute right-6 top-6 flex h-24 w-24 flex-col items-center justify-center rounded-full bg-orange-600 text-white md:right-16 md:top-16 md:h-32 md:w-32 z-10">
              <span className="text-sm font-medium md:text-base">{data.discountBadge.text}</span>
              <span className="text-2xl font-bold md:text-4xl">{data.discountBadge.percentage}</span>
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

function TimeUnit({ value, label }: { value: number; label: string }) {
  return (
    <div className="flex flex-col items-center">
      <div className="flex h-12 w-12 items-center justify-center rounded-sm bg-white text-lg font-bold text-black md:h-16 md:w-16 md:text-2xl">
        {value.toString().padStart(2, "0")}
      </div>
      <span className="mt-1 text-xs text-gray-300 md:text-sm">{label}</span>
    </div>
  );
}
